ncData.valueScript:
//====================================================================
  // Get data for drillings and rotation
  //====================================================================

  let drillings: any[] = [];
  let drills: any[] = [];
  let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);
  let insertPoint = GlobalFunc.process_MachiningInsertionHelper('012',part2.pa_Model3DGroupName)

  processings.forEach((processing) => {
    drills = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
    drills.forEach((drill) => {
      drillings.push(drill);
    });
  });

  //====================================================================
  // For each drilling (insert the drillings) Top side
  //====================================================================

  if (posRel.y > partSelf._dimy / 2) {

    drillings.forEach(x => {

      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL="102";
      DrillVert.nc_XA= posRel.x + x.YA - insertPoint.GraphicLibrary.PartOffsetX;
      DrillVert.nc_YA = partSelf._dimy - (posRel.y - part2.pa_DrillDistance + insertPoint.InsertionPointY - x.XA + insertPoint.GraphicLibrary.PartOffsetY);
      DrillVert.nc_TI=x.TI;
      DrillVert.nc_DU=x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + x.YA - insertPoint.GraphicLibrary.PartOffsetX, posRel.y - part2.pa_DrillDistance + insertPoint.InsertionPointY - x.XA + insertPoint.GraphicLibrary.PartOffsetY, 0, x.DU, x.DU, x.TI );
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'z');
    });
  }

  //====================================================================
  // For each drilling (insert the drillings) Bottom side
  //====================================================================

  else {
    drillings.forEach(x => {

      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL = "102";
      DrillVert.nc_XA = posRel.x + x.YA + insertPoint.InsertionPointY + insertPoint.GraphicLibrary.PartOffsetY;
      DrillVert.nc_YA = partSelf._dimy - (part2.pa_DrillDistance + insertPoint.InsertionPointX + x.XA + insertPoint.GraphicLibrary.PartOffsetX);
      DrillVert.nc_TI = x.TI;
      DrillVert.nc_DU = x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + x.YA + insertPoint.InsertionPointY + insertPoint.GraphicLibrary.PartOffsetY, part2.pa_DrillDistance + insertPoint.InsertionPointX + x.XA + insertPoint.GraphicLibrary.PartOffsetX, 0, x.DU, x.DU, x.TI);
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
    });
  }

//====================================================================
// Get data for drillings
//====================================================================

// Variables
let drillings: ICT_tab_HardwareDrillVertLibrary[] = [];

// Find all processings for the drawerbox (to each part)
let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);

// Find the drillings for the sidepanel
processings.forEach((processing) => {
  if(processing.ProcessingLibrary == 'DrillVertical'){
    let foundDrillings = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
    drillings = drillings.concat(foundDrillings);
  } 
});

//====================================================================
// For each drilling (insert the drillings) front connector
//====================================================================

drillings.forEach(x => 
{  
  // Position of the drill
  let PosX=posRel.x + x.XA;
  let PosY=posRel.y + x.YA;
  let PosZ=0;

  // Add Vertical Drill
  let DrillVert = this.addncout_DrillVert();
  DrillVert.nc_TOOL="102";
  DrillVert.nc_XA=PosX;
  DrillVert.nc_YA=partSelf._dimy - PosY;
  DrillVert.nc_TI=x.TI;
  DrillVert.nc_DU=x.DU;

  DrillVert.nc_BM = x.matrix_BM || "LS"
  DrillVert.nc_WI = x.matrix_WI ?? 0;
  DrillVert.nc_AB = x.matrix_AB ?? 1;
  DrillVert.nc_LA = x.matrix_LA ?? 0;
  DrillVert.nc_MI = x.matrix_MI ?? 0;
  DrillVert.nc_KO = x.matrix_KO || "00";
  DrillVert.nc_Side = "Top";  

  // Add drawing
  let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, x.DU, x.DU, x.TI );
  drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'z');
})

if (posRel.y > 0) { // If the posRel.y is bigger than 0 then it's the bottom door and we insert the 35 mm drill (front)
    //====================================================================
    // Get data for drillings and rotation
    //====================================================================

    let drillings: any[] = [];
    let drills: any[] = [];
    let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);
    let insertPoint = GlobalFunc.process_MachiningInsertionHelper('012', part2.pa_Model3DGroupName)

    processings.forEach((processing) => {
      drills = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
      drills.forEach((drill) => {
        drillings.push(drill);
      });
    });

    //====================================================================
    // For each drilling (insert the drillings)
    //====================================================================

    drillings.forEach(x => {
      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL = "102";
      DrillVert.nc_XA = posRel.x + x.YA + insertPoint.InsertionPointY + insertPoint.GraphicLibrary.PartOffsetY;
      DrillVert.nc_YA = partSelf._dimy - (partSelf._dimy - part2.pa_DrillDistance - insertPoint.InsertionPointX - x.XA - insertPoint.GraphicLibrary.PartOffsetX);
      DrillVert.nc_TI = x.TI;
      DrillVert.nc_DU = x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + x.YA + insertPoint.InsertionPointY + insertPoint.GraphicLibrary.PartOffsetY, partSelf._dimy - part2.pa_DrillDistance - insertPoint.InsertionPointX - x.XA - insertPoint.GraphicLibrary.PartOffsetX, 0, x.DU, x.DU, x.TI);
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
    });
  }
  else { // If the posRel.y is smaller than 0 then it's the top door and we insert the mounting plate drills (Carcase)
    //====================================================================
    // Get data for drillings and rotation
    //====================================================================

    let drillings: any[] = [];
    let drills: any[] = [];
    let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId2);
    let insertPoint = GlobalFunc.process_MachiningInsertionHelper('012',part2.pa_Model3DGroupName2)
    let dimz=99; // DimZ of part_hingeDrill (Fixed in mc_Hinge)

    processings.forEach((processing) => {
      drills = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Carcase');
      drills.forEach((drill) => {
        drillings.push(drill);
      });
    });

    //====================================================================
    // For each drilling (insert the drillings)
    //====================================================================

    drillings.forEach(x => 
    {  
      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL="102";
      DrillVert.nc_XA=posRel.x + insertPoint.InsertionPointY + x.YA;
      DrillVert.nc_YA = partSelf._dimy - ( insertPoint.InsertionPointZ + x.XA);
      DrillVert.nc_TI=x.TI;
      DrillVert.nc_DU=x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";  

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + insertPoint.InsertionPointY + x.YA,  insertPoint.InsertionPointZ + x.XA, 0, x.DU, x.DU, x.TI );
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'z');
    });
  }
